import{_ as l,o as e,c as i,a0 as t}from"./chunks/framework.CSGB4SNl.js";const q=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"java/eight-legged essay/java-hot200-day04.md","filePath":"java/eight-legged essay/java-hot200-day04.md"}'),o={name:"java/eight-legged essay/java-hot200-day04.md"};function r(s,a,n,h,d,c){return e(),i("div",null,[...a[0]||(a[0]=[t('<h4 id="mysql中有哪些锁" tabindex="-1">mysql中有哪些锁 <a class="header-anchor" href="#mysql中有哪些锁" aria-label="Permalink to &quot;mysql中有哪些锁&quot;">​</a></h4><ol><li>按照锁的粒度和模式来分</li><li>粒度：表锁和行锁，表锁具体锁住某个表，行锁包含记录锁和间隙锁，记录锁具体锁住某一行，间隙锁锁住两行数据的间隙不让其它数据插入这个间隙,临键锁就是前两者的组合</li><li>模式：排他锁，不让其它事务读，共享锁允许多个事务读</li><li>意向锁，来记录表里面是否有行锁，这样加表锁的时候就不用去遍历是否有行锁，元数据锁保护表结构(和事务绑定，事务回滚释放，确保读写和改结构不能同时操作)，插入意向锁表示这个事务正在往两行数据的间隙插入，自增锁保证自增时id不重复</li><li>没走索引触发全表扫描就表锁了，线上加字段超时，可能是长事务导致mdl锁没释放，查询就卡死等待了</li></ol><h4 id="策略模式" tabindex="-1">策略模式 <a class="header-anchor" href="#策略模式" aria-label="Permalink to &quot;策略模式&quot;">​</a></h4><ol><li>简单来说，就是策略，调用方-客户端可以通过不同条件采用不同策略，且各个策略间可以相互转化，持有策略上下文，传入不同对象实现不同策略，比如支付（支付宝、微信、银行卡），向支付上下文对象传入wechatxxx策略对象就可以调用微信支付方法之类的</li></ol><h4 id="mysql的悲观锁和乐观锁" tabindex="-1">mysql的悲观锁和乐观锁 <a class="header-anchor" href="#mysql的悲观锁和乐观锁" aria-label="Permalink to &quot;mysql的悲观锁和乐观锁&quot;">​</a></h4><ol><li>悲观锁是一种悲观心态看待问题，就是假设冲突一定会发生，之间加锁，等到这个事务执行完才释放锁，乐观锁的话就是先去执行，真冲突了再处理，就常用的版本号，查询的时候先查询版本号，后面逻辑where连带版本号一起查，如果版本号不一致在业务代码中处理</li><li>乐观锁更新失败率很高怎么办：分桶将一个库存字段拆成10个，每次请求打到不同的桶上，冲突概率降10倍,合并请求队列收集一段时间请求，然后进行批处理，最保障的还是加悲观锁去排队</li></ol><h4 id="死锁如何解决" tabindex="-1">死锁如何解决 <a class="header-anchor" href="#死锁如何解决" aria-label="Permalink to &quot;死锁如何解决&quot;">​</a></h4><ol><li>自动和手动，自动的话innoDB有个自动处理死锁的参数配置，默认是开启的，就会自动决策最小代价回滚释放锁，还有就是锁等待超时，设置锁等待超时时间，超时就自动释放锁，回滚,手动干预的话就是去查日志找到相互等待的两个事务分别持有什么锁，去锁表里面找相关的阻塞进程id，然后kill掉</li><li>什么情况下会考虑关掉死锁自动处理配置，因为本身死锁检测是有代价的，高并发场景下消耗很大，这时候就可以考虑使用锁等待超时，配置较低时间，然后代码层去做重试</li></ol><h4 id="三个count有什么区别" tabindex="-1">三个count有什么区别 <a class="header-anchor" href="#三个count有什么区别" aria-label="Permalink to &quot;三个count有什么区别&quot;">​</a></h4><ol><li>性能上来讲的话，count(*)/count(1)性能强点，count(字段名的话因为要处理null值，而前两者会把null一起算入，且如果没走索引的话就会全表扫描，这也是性能开销)</li><li>count(*)太慢如何优化，首先如果允许一定范围误差则show table status最快，但是会有一定误差，如果既要精度又要速度的话就走缓存了，redis维护一个计数器，然后注意缓存和数据库一致性问题，定期校对吧</li></ol><h4 id="观察者模式" tabindex="-1">观察者模式 <a class="header-anchor" href="#观察者模式" aria-label="Permalink to &quot;观察者模式&quot;">​</a></h4><ol><li>类似发布订阅这样的一对多模式吧，就是要有被观察者和观察者，被观察者动态变化是，观察者会接收到广播消息然后进行处理</li><li>多用于事件监听、消息推送、还有前端响应式这种</li></ol><h4 id="如何进行sql调优" tabindex="-1">如何进行sql调优 <a class="header-anchor" href="#如何进行sql调优" aria-label="Permalink to &quot;如何进行sql调优&quot;">​</a></h4><ol><li>索引层面：合理设计联合索引，只加常用的必要字段减少回表查询次数，查询时避免在条件里面写表达式和函数，避免对索引那一列进行运算或函数调用，会降低查询性能，注意条件顺序，尽量匹配最左原则</li><li>sql写法方面：避免select * 只查必要字段，避免&#39;%LIKE&#39;前缀查询，必然全表扫描</li><li>还有就是分库分表、读写分离、缓存,业务层面减少不必要的字段，减少多表联查，可以改成分批查询</li><li>索引列类型也要注意，如果出现隐式类型转化就失效了</li></ol>',14)])])}const m=l(o,[["render",r]]);export{q as __pageData,m as default};
